#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        if(N==2||N==3){
            printf("-1\n");
            continue;
        }
        if(N==4){
            printf("2 4 1 3\n");
            continue;
        }
        int first=1;
        for(int i=1;i<=N;i+=2){
            if(i>1) printf(" ");
            printf("%d",i);
            first=0;
        }
        for(int i=2;i<=N;i+=2){
            printf(" %d",i);
        }
        printf("\n");
    }
    return 0;
}

